function search(query) {
    if (!query) return [];
    var q = String(query).toLowerCase();
    var results = [];
    for (var ch in NAMES) {
        var ns = NAMES[ch];
        for (var i = 0; i < ns.length; i++) {
            if (ns[i].indexOf(q) !== -1) { results.push(ch); break; }
        }
        if (results.length >= 200) break;
    }
    return results;
}
